sql:
SELECT species
FROM pollinators
WHERE species = 'ternarius';

SELECT COUNT(*) 
FROM pollinators 
WHERE collected_by = 'Sara Clark';

external_knowledge:
- A "specific species" refers to a species with ID 0; 
- A "particular collector" refers to a collector with ID 0; 
- "Forest" refers to a land use type with a specific name, not just a general term.

sql:
SELECT DISTINCT air_temperature_c
FROM pollinators
ORDER BY air_temperature_c;

SELECT AVG(cc.average_wind_speed_kmh) AS overall_average_wind_speed
FROM pollinators p
INNER JOIN climate_conditions cc ON p.weather_condition_id = cc.climate_id;

SELECT COUNT(DISTINCT pollinator_id) AS unique_pollinators_count
FROM pollinators
WHERE origin_facility = 1;
